import json
import re

try:
    api_data = json.loads('''{{api_raw_product_data}}''') if isinstance('''{{api_raw_product_data}}''', str) else '''{{api_raw_product_data}}'''
    ana_data = json.loads('''{{product_analyze}}''') if isinstance('''{{product_analyze}}''', str) else '''{{product_analyze}}'''

    names = []
    if isinstance(ana_data, dict):
        names = ana_data.get('name', [])
        if isinstance(names, str):
            names = [names]
    elif isinstance(ana_data, list):
        names = ana_data

    PRODUCTS = []
    if isinstance(api_data, list) and len(api_data) > 0 and isinstance(api_data[0], dict) and 'data' in api_data[0]:
        PRODUCTS = api_data[0]['data']
    elif isinstance(api_data, list):
        PRODUCTS = api_data

    content = ""
    i = 1
    sel = []

    def normalize(s):
        return re.sub(r'[^\w\s]', '', str(s)).strip().lower()

    for product in PRODUCTS:
        if not isinstance(product, dict): continue
        title = product.get('name', '')
        if not title: title = product.get('Tên sản phẩm', '')
        title_norm = normalize(title)

        matched = False
        for n in names:
            n_norm = normalize(n)
            if n_norm and (n_norm in title_norm or title_norm in n_norm):
                matched = True
                break

        if matched:
            price = product.get('price', 'N/A')
            if price == 'N/A': price = product.get('Giá tiền', 'Liên hệ')
            try:
                price_num = float(str(price).replace(',', '').replace('.', ''))
                price_formatted = f"{int(price_num):,}".replace(",", ".")
            except:
                price_formatted = str(price)

            img = product.get('link_image', 'N/A')
            if img == 'N/A': img = product.get('Ảnh', 'N/A')

            desc = product.get('full_description', '')
            if not desc: desc = product.get('Công dụng', '')
            desc = str(desc).replace('\n', '').strip()

            for keyword in ['Thành phần:', 'Công dụng:', 'Chỉ định:', 'Hướng dẫn sử dụng:', 'Cách dùng:']:
                desc = desc.replace(keyword, f"**{keyword}**")

            info = f"**{i}. {title}**\n"
            if img and img != 'N/A': info += f"![Ảnh sản phẩm]({img})\n"
            info += f"**Giá tham khảo:** {price_formatted} VNĐ\n\n"
            info += f"{desc}\n"

            keywords = product.get('keywords', '')
            if keywords and keywords != 'N/A': info += f"**Đặc điểm nổi bật:** {keywords}\n"

            link = product.get('link_product', '')
            if link and link != 'N/A': info += f"[Link sản phẩm]({link})\n"

            info += "\n\n"

            if info not in sel:
                sel.append(info)
                content += info
                i += 1

    if not content.strip():
        print("Dạ em không tìm thấy sản phẩm phù hợp. Anh/chị có thể cho em xin thêm thông tin được không ạ?")
    else:
        print(content.strip())

except Exception as e:
    print("Dạ em đang gặp chút khó khăn khi tìm kiếm sản phẩm. Anh/chị đợi em một chút nhé!")

reply = '''{{bot_b2c_reply}}'''
knowledge = '''{{knowledge_from_rag}}'''

def extract_urls(text):
    urls = []
    i = 0
    while i < len(text):
        start = -1
        if text[i:i+8] == 'https://':
            start = i
        elif text[i:i+7] == 'http://':
            start = i
        if start >= 0:
            end = start
            while end < len(text) and text[end] not in ' \n\r\t)]\"\'>':
                end = end + 1
            url = text[start:end].rstrip('.,;:!?')
            if len(url) > 10:
                urls.append(url)
            i = end
        else:
            i = i + 1
    return urls

urls_in_reply = extract_urls(reply)

if len(urls_in_reply) > 0 and len(knowledge.strip()) > 0:
    urls_in_knowledge = extract_urls(knowledge)
    knowledge_url_set = {}
    for u in urls_in_knowledge:
        knowledge_url_set[u] = True

    for url in urls_in_reply:
        if url not in knowledge_url_set:
            lines = reply.split('\n')
            new_lines = []
            for line in lines:
                if url not in line:
                    new_lines.append(line)
            reply = '\n'.join(new_lines)

while '\n\n\n' in reply:
    reply = reply.replace('\n\n\n', '\n\n')

output = reply
print(output)
